import React from 'react';

export default function ConfigPanel({
  availableProjects,
  selectedProjects,
  statusFilter,
  onProjectsChange,
  onStatusFilterChange,
  onSave,
  onClose,
}) {
  function toggleProject(key) {
    if (selectedProjects.includes(key)) {
      onProjectsChange(selectedProjects.filter((k) => k !== key));
    } else {
      onProjectsChange([...selectedProjects, key]);
    }
  }

  return (
    <div style={styles.panel}>
      {/* Header */}
      <div style={styles.header}>
        <span style={styles.title}>Configure View</span>
        <button style={styles.closeBtn} onClick={onClose}>✕</button>
      </div>

      <div style={styles.body}>
        {/* Status filter */}
        <div style={styles.section}>
          <div style={styles.sectionTitle}>Status filter</div>
          <label style={styles.radioLabel}>
            <input
              type="radio"
              value="active"
              checked={statusFilter === 'active'}
              onChange={() => onStatusFilterChange('active')}
            />
            <span>Active issues only (exclude Done)</span>
          </label>
          <label style={styles.radioLabel}>
            <input
              type="radio"
              value="all"
              checked={statusFilter === 'all'}
              onChange={() => onStatusFilterChange('all')}
            />
            <span>All issues</span>
          </label>
        </div>

        {/* Project picker */}
        <div style={styles.section}>
          <div style={styles.sectionTitle}>
            Projects
            <span style={styles.selectedCount}> ({selectedProjects.length} selected)</span>
          </div>
          <div style={styles.projectList}>
            {availableProjects.slice(0, 60).map((p) => (
              <label key={p.key} style={styles.projectOption}>
                <input
                  type="checkbox"
                  checked={selectedProjects.includes(p.key)}
                  onChange={() => toggleProject(p.key)}
                />
                <span style={styles.projectKey}>{p.key}</span>
                <span style={styles.projectName}>{p.name}</span>
              </label>
            ))}
          </div>
        </div>
      </div>

      {/* Footer */}
      <div style={styles.footer}>
        <button style={styles.cancelBtn} onClick={onClose}>Cancel</button>
        <button style={styles.saveBtn} onClick={onSave}>Save to view</button>
      </div>
    </div>
  );
}

const styles = {
  panel: {
    position: 'absolute',
    right: 0,
    top: 0,
    bottom: 0,
    width: '300px',
    background: '#fff',
    borderLeft: '1px solid #DFE1E6',
    zIndex: 20,
    display: 'flex',
    flexDirection: 'column',
    boxShadow: '-4px 0 16px rgba(0,0,0,0.1)',
  },
  header: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    padding: '14px 16px',
    borderBottom: '1px solid #DFE1E6',
  },
  title: {
    fontWeight: 700,
    fontSize: '14px',
    color: '#172B4D',
  },
  closeBtn: {
    background: 'none',
    border: 'none',
    cursor: 'pointer',
    fontSize: '14px',
    color: '#6B778C',
    padding: '4px',
  },
  body: {
    flex: 1,
    overflowY: 'auto',
    padding: '16px',
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
  },
  section: {
    display: 'flex',
    flexDirection: 'column',
    gap: '8px',
  },
  sectionTitle: {
    fontSize: '11px',
    fontWeight: 700,
    color: '#6B778C',
    textTransform: 'uppercase',
    letterSpacing: '0.5px',
    marginBottom: '4px',
  },
  selectedCount: {
    textTransform: 'none',
    fontWeight: 400,
    color: '#97A0AF',
  },
  radioLabel: {
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
    fontSize: '13px',
    color: '#172B4D',
    cursor: 'pointer',
    padding: '3px 0',
  },
  projectList: {
    maxHeight: '360px',
    overflowY: 'auto',
    border: '1px solid #DFE1E6',
    borderRadius: '4px',
    padding: '4px 0',
  },
  projectOption: {
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
    padding: '6px 10px',
    cursor: 'pointer',
    fontSize: '12px',
  },
  projectKey: {
    fontWeight: 700,
    color: '#0052CC',
    minWidth: '48px',
    flexShrink: 0,
  },
  projectName: {
    color: '#172B4D',
    overflow: 'hidden',
    textOverflow: 'ellipsis',
    whiteSpace: 'nowrap',
  },
  footer: {
    display: 'flex',
    justifyContent: 'flex-end',
    gap: '8px',
    padding: '12px 16px',
    borderTop: '1px solid #DFE1E6',
  },
  cancelBtn: {
    background: 'none',
    border: '1px solid #DFE1E6',
    borderRadius: '4px',
    padding: '7px 14px',
    cursor: 'pointer',
    fontSize: '13px',
    color: '#172B4D',
  },
  saveBtn: {
    background: '#0052CC',
    color: '#fff',
    border: 'none',
    borderRadius: '4px',
    padding: '7px 14px',
    cursor: 'pointer',
    fontSize: '13px',
    fontWeight: 600,
  },
};
